-- main.bi_output.cb (TABLE, 35 columns)
ALTER TABLE main.bi_output.cb ALTER COLUMN `OpeningBalance` COMMENT 'Same as DateID: Date identifier in YYYYMMDD integer format. Clustered index column. The date this balance snapshot represents. Filter on this column for efficient date-range queries. (Tier 2 - SP_Client_Balance_New). (Propagated from main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new, rename chain: DateID -> OpeningBalance)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `CompensationDormantFee` COMMENT 'Dormant fee compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (30). Refunds of inactivity fees charged to dormant accounts. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `TransferCoins` COMMENT 'Crypto coin transfers. -SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=8 AND IsRedeem=1. Blockchain wallet-to-wallet movements (sign-inverted). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `OpeningBalance` COMMENT 'Customer''s balance at the start of the business day (in USD). Equals the previous day''s ClosingBalance for this CID. Source: V_Liabilities (previous day). For the first row per CID, this is the initial deposit amount. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `NetTransfersUnrealizedPnL` COMMENT 'Unrealized PnL component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `ClientBalanceRealizedPnL` COMMENT 'Total realized PnL. SUM(NetProfit) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40). All closed positions across all asset classes. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `CompensationToAffiliate` COMMENT 'Affiliate compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (8,51,52). Payouts to affiliate/partner accounts. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `TransferCoinFees` COMMENT 'Crypto transfer fees. -SUM(Commission) from Fact_CustomerAction WHERE ActionTypeID=30 AND IsRedeem=1. Blockchain network + eToro transfer fees. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `Cashouts` COMMENT 'Cashout withdrawals. SUM(Amount) from Fact_CustomerAction WHERE (ActionTypeID=8 AND IsRedeem!=1) OR ActionTypeID=45. Excludes crypto redemptions (IsRedeem=1). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `UnrealizedPnLChange` COMMENT 'Day-over-day change in total unrealized PnL across all asset classes. Key metric for equity volatility tracking. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `CID` COMMENT 'Customer ID. The eToro platform''s primary customer identifier (RealCID from Fact_SnapshotCustomer). HASH distribution key. One or two rows per CID per DateID depending on transfer status. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `OvernightFee` COMMENT 'Overnight/rollover fees. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35. CFD swap fees charged for holding positions overnight/weekend. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `ClosingBalance` COMMENT 'Customer''s balance at end of business day (USD). From V_Liabilities. Tomorrow''s OpeningBalance = today''s ClosingBalance. The cycle equation must hold: OpeningBalance + all flows = ClosingBalance. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `Deposits` COMMENT 'Total deposits. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID IN (7,44). Includes both external deposits (7) and internal transfers (44). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `Refund` COMMENT 'Refund amounts. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=12. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `Foreclosure` COMMENT 'Foreclosure amounts. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (32). Forced position closures due to margin calls or regulatory requirements. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `ChargebackLoss` COMMENT 'Loss from chargebacks that could not be recovered. Split by TransferDirection for regulation transfer CIDs. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `Chargeback` COMMENT 'Chargeback amounts. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID IN (11,13). Disputed deposit reversals. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `LostDebt` COMMENT 'Lost debt write-off. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (31). Uncollectable amounts written off. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `CashoutFee` COMMENT 'Cashout fee. -SUM(Commission) + SUM(CASE WHEN IsRedeem=1 THEN Commission END) from Fact_CustomerAction WHERE ActionTypeID=30. Excludes crypto redemption commissions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `NetTransfersNWA` COMMENT 'NWA (Net Withdrawable Amount) component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `CompensationPnLAdjustments` COMMENT 'PnL adjustment compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (22). Corrections to realized PnL via compensation mechanism. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `UnrealizedCommissionChange` COMMENT 'Day-over-day change in total unrealized commission. Commission accrued but not yet realized (positions still open). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cb ALTER COLUMN `CompensationDeposit` COMMENT 'Deposit-type compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID = 7. (Tier 2 - SP_Client_Balance_New)';
