-- main.bi_output.cbr_ind (TABLE, 31 columns)
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `NetTransfersUnrealizedPnL` COMMENT 'Unrealized PnL component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `OvernightFee` COMMENT 'Overnight/rollover fees. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35. CFD swap fees charged for holding positions overnight/weekend. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `LostDebt` COMMENT 'Lost debt write-off. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (31). Uncollectable amounts written off. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `UsedBonus` COMMENT 'Bonus credit amount currently used in open positions. Change metric (day-over-day). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `TicketFee` COMMENT 'Fixed ticket fee. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=1000 (synthetic type for fixed-amount ticket fees). Separated from TradingFees per SR-262975 (Jul 2024). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `NWAAdjustment` COMMENT 'NWA adjustment compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (19). Adjustments to Net Withdrawable Amount. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `TransferCoins` COMMENT 'Crypto coin transfers. -SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=8 AND IsRedeem=1. Blockchain wallet-to-wallet movements (sign-inverted). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `UnrealizedCommissionChange` COMMENT 'Day-over-day change in total unrealized commission. Commission accrued but not yet realized (positions still open). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `CompensationDeposit` COMMENT 'Deposit-type compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID = 7. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `Foreclosure` COMMENT 'Foreclosure amounts. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (32). Forced position closures due to margin calls or regulatory requirements. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `CompensationPnLAdjustments` COMMENT 'PnL adjustment compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (22). Corrections to realized PnL via compensation mechanism. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `Cashouts` COMMENT 'Cashout withdrawals. SUM(Amount) from Fact_CustomerAction WHERE (ActionTypeID=8 AND IsRedeem!=1) OR ActionTypeID=45. Excludes crypto redemptions (IsRedeem=1). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `Refund` COMMENT 'Refund amounts. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=12. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `NetTransfersLiability` COMMENT 'Liability component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `UnrealizedPnLChange` COMMENT 'Day-over-day change in total unrealized PnL across all asset classes. Key metric for equity volatility tracking. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `CompensationToAffiliate` COMMENT 'Affiliate compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (8,51,52). Payouts to affiliate/partner accounts. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `CompensationCashouts` COMMENT 'Cashout-type compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (33). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `Compensation` COMMENT 'General compensation. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=36 AND CompensationReasonID NOT IN (7,8,11,18,19,22,30,31,32,33,34,36,37,38,40,41,50,51,52). Excluded IDs are captured in dedicated columns (7=CompDeposit, 8/51/52=Affiliate, 11=NegRefill, 19=NWAAdj, 22=PnLAdj, 30=DormantFee, 31=LostDebt, 32=Foreclosure, 33=CompCashout, 41/50=PI). Reason 17 re-included per SR-280376 (Nov 2024). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `CompensationDormantFee` COMMENT 'Dormant fee compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (30). Refunds of inactivity fees charged to dormant accounts. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `Chargeback` COMMENT 'Chargeback amounts. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID IN (11,13). Disputed deposit reversals. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `NetTransfersNWA` COMMENT 'NWA (Net Withdrawable Amount) component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `ClientBalanceRealizedPnL` COMMENT 'Total realized PnL. SUM(NetProfit) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40). All closed positions across all asset classes. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `SDRT` COMMENT 'Stamp Duty Reserve Tax (UK). SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35 AND IsFeeDividend=3. Tax on UK stock purchases. Added Oct 2023. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `Deposits` COMMENT 'Total deposits. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID IN (7,44). Includes both external deposits (7) and internal transfers (44). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `CompensationPI` COMMENT 'PI compensation. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=36 AND CompensationReasonID IN (41,50). Performance Incentive payouts to popular investors. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `CashoutFee` COMMENT 'Cashout fee. -SUM(Commission) + SUM(CASE WHEN IsRedeem=1 THEN Commission END) from Fact_CustomerAction WHERE ActionTypeID=30. Excludes crypto redemption commissions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `ChargebackLoss` COMMENT 'Loss from chargebacks that could not be recovered. Split by TransferDirection for regulation transfer CIDs. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `TransferCoinFees` COMMENT 'Crypto transfer fees. -SUM(Commission) from Fact_CustomerAction WHERE ActionTypeID=30 AND IsRedeem=1. Blockchain network + eToro transfer fees. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `NegativeRefill` COMMENT 'Negative balance protection refill. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (11). Platform refills retail client balance to zero after CFD/futures losses exceed available funds. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `DividendsPaid` COMMENT 'Dividend payments. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35 AND IsFeeDividend=1. Real stock and ETF holders receive dividends. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.cbr_ind ALTER COLUMN `OtherNegatives` COMMENT 'Other negative balance adjustments not captured in specific columns. Split by TransferDirection for regulation transfer CIDs. Catch-all for miscellaneous balance reductions. (Tier 2 - SP_Client_Balance_New)';

-- main.bi_output.final (TABLE, 7 columns)
ALTER TABLE main.bi_output.final ALTER COLUMN `RollOverFee` COMMENT 'Same as DividendsPaid: Dividend payments. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35 AND IsFeeDividend=1. Real stock and ETF holders receive dividends. (Tier 2 - SP_Client_Balance_New). (Propagated from main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new, rename chain: DividendsPaid -> RollOverFee)';
ALTER TABLE main.bi_output.final ALTER COLUMN `RollOver_and_Divivdends` COMMENT 'Same as OvernightFee: Overnight/rollover fees. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35. CFD swap fees charged for holding positions overnight/weekend. (Tier 2 - SP_Client_Balance_New). (Propagated from main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new, rename chain: OvernightFee -> RollOver_and_Divivdends)';
ALTER TABLE main.bi_output.final ALTER COLUMN `rn` COMMENT 'Same as CID: Customer ID. The eToro platform''s primary customer identifier (RealCID from Fact_SnapshotCustomer). HASH distribution key. One or two rows per CID per DateID depending on transfer status. (Tier 2 - SP_Client_Balance_New). (Propagated from main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new, rename chain: CID -> rn)';
ALTER TABLE main.bi_output.final ALTER COLUMN `Regulation` COMMENT 'Name of the regulatory entity governing this customer row. Values: FCA, CySEC, ASIC, SIBA, SFSA, FSA, etc. Resolved from Dim_Regulation.Name via Fact_SnapshotCustomer.RegulationID. For transfer CIDs, the -1 row shows the previous regulation. (Tier 1 - Dictionary.Regulation)';
ALTER TABLE main.bi_output.final ALTER COLUMN `CID` COMMENT 'Customer ID. The eToro platform''s primary customer identifier (RealCID from Fact_SnapshotCustomer). HASH distribution key. One or two rows per CID per DateID depending on transfer status. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_output.final ALTER COLUMN `Divivdends` COMMENT 'Same as DividendsPaid: Dividend payments. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35 AND IsFeeDividend=1. Real stock and ETF holders receive dividends. (Tier 2 - SP_Client_Balance_New). (Propagated from main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new, rename chain: DividendsPaid -> Divivdends)';
ALTER TABLE main.bi_output.final ALTER COLUMN `RollOverFee` COMMENT 'Same as OvernightFee: Overnight/rollover fees. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35. CFD swap fees charged for holding positions overnight/weekend. (Tier 2 - SP_Client_Balance_New). (Propagated from main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new, rename chain: OvernightFee -> RollOverFee)';
